mapper.select:
SELECT image_url
FROM place_image
WHERE place_id = #{placeId}

SELECT * FROM (
    SELECT
        ,
        (
            6371 * ACOS(
                COS(WIDTH_BUCKET(#{mapY}, -90, 90, 180)) * COS(WIDTH_BUCKET(p.latitude, -90, 90, 180))
            )
        ) AS distance
    FROM place p
    WHERE p.place_id != #{placeId}
      AND p.longitude IS NOT NULL
      AND p.latitude IS NOT NULL
) 
WHERE ROWNUM <= #{limit}
ORDER BY id DESC
